// // This module implements a 2-to-1 multiplexer that selects one of two 32-bit input data lines (in0 or in1) based on the value of the select signal (s0). When s0 is low (0), the output (out) will be equal to in1; when s0 is high (1), the output will be equal to in0.
module top_module(out, in0, in1, s0);output reg [31:0] out;
input [31:0] in0, in1;
input s0;

always @(*) begin
	case(s0)
	1'b0: out = in0;
	1'b1: out = in1;
	default: out = 32'hxxxxxxxx;
	endcase
end
endmodule
